SELECT m.ms_id as msId, m.title as title, u.full_name as authorName, u.unit as authorUnit, DATE_FORMAT(m.submit_time, '%Y-%m-%d %H:%i:%s') as submitTime, m.status as status FROM manuscript m JOIN user u ON m.submitter_id = u.user_id WHERE m.status = 'Submitted'
AND ( m.title LIKE CONCAT('%', #{keyword}, '%') OR m.ms_id LIKE CONCAT('%', #{keyword}, '%') OR u.full_name LIKE CONCAT('%', #{keyword}, '%') OR u.unit LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY m.submit_time DESC LIMIT #{offset}, #{pageSize}

